var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同一時間"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"으아아아아아아아……!","JPN":"うわああああああ……！","ENG":"Aaaaagh...!","TWN":"呃啊啊啊啊啊啊！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"정신 차려, 꼬맹이!","JPN":"しっかりしろよ、おこちゃま！","ENG":"Get it together, kid!","TWN":"打起精神來，小鬼！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"착지…! 착지해야 해! 꽉 잡으라고……!!","JPN":"着地……！　着地しないと！　しっかり捕まってろ……！！","ENG":"We're landing...! We've gotta land! Hold on tight...!!","TWN":"著陸！必須著陸！抓緊點！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"하아아…! 그 망할 쥐돌이 자식……!","JPN":"はああ……！　あのクソネズミ野郎……！","ENG":"*Sigh...!* That damn rat-girl...!","TWN":"哈啊啊！那個該死的老鼠！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"싱글 다이빙인지, 뭔지 하더니… 하마터면 진짜 독신으로 죽을 뻔했잖아……?","JPN":"シングルダイビングはどうのこうの言ってたけど……一歩間違えば冗談じゃなく独身で死ぬところだったぞ……！","ENG":"Single dive? Yeah right... I almost died single for real...!","TWN":"說是單人躍入什麼的……差點真的單身到死了……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"야, 꼬맹이! 너는 괜찮냐? 어디 까지거나, 부러진 데 없어?","JPN":"おい、おこちゃま！　大丈夫か？　擦りむいたり、折れたりしてないか？","ENG":"Hey, you okay, kid? Nothing twisted or broken?","TWN":"喂，小鬼！沒事吧？有沒有摔傷或者骨折？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"말도 마요. 라이카가 잡아줘서 겨우 살았어요.","JPN":"もうボロボロよ。ライカが捕まえてくれて助かったわ。","ENG":"Don't even ask. I barely survived thanks to you catching me.","TWN":"別提了，多虧了萊卡抓住我，我才活了下來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"고마워요, 라이카.","JPN":"ありがとう、ライカ。","ENG":"Thanks, Laika.","TWN":"謝謝你，萊卡。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"알았으니까, 그럼 빨리 내려오기나 해. 무거워, 뚱냥아.","JPN":"わかったから早く降りろよ。重いんだよ、デブ猫。","ENG":"Yeah, yeah. Now get off already. You're heavy, chubcat.","TWN":"知道了，那就快點下來。好重啊，胖喵。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"뚱냥이!? 저 하나도 안 무겁거든요!?","JPN":"デブ猫！？　私のどこが重いっていうの！！","ENG":"Chubcat?! I am not heavy at all!","TWN":"胖喵！？我一點也不重啊！？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그나저나 일단 도착하긴 했는데…….","JPN":"それにしても、とりあえず到着はしたけど……","ENG":"Anyway, we made it...","TWN":"總之，到是到了……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"대체 여긴 어디야? 하늘이 시뻘건데? 원래 이면세계라는 게 다 이런 건가……?","JPN":"いったいどこだここ？　空真っ赤だし。裏世界って全部こうなのか……？","ENG":"Where are we? The sky's blood-red. Is this what the Counterside always looks like...?","TWN":"這到底是哪裡？天空怎麼是紅色的？原來異界就是這樣的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐야, 그럼 라이카도 이게 첫 다이브인 거예요?","JPN":"なんだ、じゃあライカもこれが初ダイブなの？","ENG":"Huh? Is this is your first dive too, Laika?","TWN":"什麼？難道萊卡也是第一次躍入嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"꼬맹이. 어른이라고 뭐든 익숙할 거라고 여기는 건 착각이야.","JPN":"おこちゃま。大人ならなんでも慣れてると思うのは勘違いだぞ。","ENG":"Kid. Just because I'm an adult doesn't mean I've done everything.","TWN":"小鬼，別以為大人就都有經驗。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"누구든 처음은 있는 법이라고. 우주에는 가봤어도, 이면세계는 처음이야.","JPN":"誰にでも初めてはあるんだ。宇宙に行ったことはあるけど、裏世界は初めてだよ。","ENG":"Everyone has a first time. I've been to space, but not the Counterside.","TWN":"誰都有第一次嘛。雖然去過宇宙，但還是第一次去異界。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"근데 왜 지금까지 아무 말 안 했어요?","JPN":"どうして今まで黙ってたの？","ENG":"Then why didn't you say anything till now?","TWN":"那你為什麼到現在都沒說過呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"얌마! 네가 처음이라고 했는데, 나까지 처음이라고 하면 쪽팔리잖냐!","JPN":"おい！　あんたが初めてなんて言ってるのに、私まで実は同じなんだって言ったら恥ずかしいだろ！","ENG":"Come on! You said it was your first time, and if I said that too, how'd that make me look?!","TWN":"喂！你都說你是第一次了，如果我也說是第一次，那多丟臉啊！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"에휴, 하여간 어른답지 못하다니까.","JPN":"もう、全然大人らしくないんだから。","ENG":"*Sigh* So much for acting like an adult.","TWN":"唉，你真的很幼稚。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"역시 침식파 때문에 현실과 통신 연결은 안 되나…….","JPN":"やっぱり侵食波のせいで現実との通信は繋がらないのかな……","ENG":"Looks like we really can't connect to reality. It must be the Corruption ray blocking signals...","TWN":"果然因為侵蝕波，無法與現實進行通訊連接……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"어쨌든 박사님이 여기부턴 망원경이 길을 알려줄 거라고 했어요.","JPN":"とにかく博士が、ここからは望遠鏡が道案内をしてくれるって言ってたわ。","ENG":"Anyway, the doctor said the Telescope would guide us from here.","TWN":"不管怎麼說，博士說過從這裡開始望遠鏡會指引我們前進。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"Okay then...","TWN":"所以……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"외장 아스트라 드라이브 삽입…! 벡터 변환 필드 전개……!","JPN":"外装アストラ・ドライブ挿入……！　ベクター変換フィールド展開……！","ENG":"Inserting the external Astra Drive...! Deploying vector conversion field...!","TWN":"外置艾斯特拉引擎插入…！向量轉換場展開…！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"신성 관측 프로토콜 기동!","JPN":"神聖観測プロトコル起動！","ENG":"Divinity Observation Protocol, activated!","TWN":"啟動神聖觀測協定！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"라이카, 망원경이 반응하고 있어요!","JPN":"ライカ、望遠鏡が反応してるわ！","ENG":"Laika, the Telescope's picking up something!","TWN":"萊卡，望遠鏡有反應了！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"아무래도 목적지는 제대로 찾아온 것 같은데요?","JPN":"どうやらちゃんと目的地には着いたみたい。","ENG":"Looks like we're in the right place after all!","TWN":"看來我們找對目的地了呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"아아, 그건 다행인데 말이야…….","JPN":"ああ、それはよかったけど……","ENG":"Well, that's a relief...","TWN":"啊啊，那真是萬幸啊……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"한 가지 사소한 문제가 발생한 것 같은데……?","JPN":"一つだけ些細な問題が発生したみたいだ……","ENG":"Except, we've got one tiny problem on our hands...","TWN":"但好像出現了一個小問題？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"문제라고요?","JPN":"問題？","ENG":"A problem...?","TWN":"你說有問題？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"일단, 내 뒤로 물러서라고. 꼬맹이.","JPN":"とりあえず、私の後ろに下がれ、おこちゃま。","ENG":"Get behind me, kid.","TWN":"總之，你先退到我後面去，小鬼。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L7_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이거 순식간에 포위당해 버렸잖아? 도착하자마자 침식체랑 구르게 생겼네.","JPN":"あっという間に囲まれちゃったな。到着するなり侵食体と戦闘か。","ENG":"They've got us completely surrounded. Great, rolling with C.O.s the moment we land.","TWN":"我們瞬間就被包圍了，剛到就要和侵蝕體打起來了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_09"},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"숫자가 너무 많아요. 정면으로 돌파하기에는 무리야.","JPN":"数が多すぎるわ。正面突破は無理よ。","ENG":"There are way too many. We can't break through head-on.","TWN":"數量太多了，正面突破太勉強了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"쳇, 귀찮게 됐지만 어쩔 수 없지……!","JPN":"ちっ、面倒くさいけど仕方ない……！","ENG":"Tch, such a pain in the neck. But guess we've got no choice...!","TWN":"嘖，雖然有點麻煩，但沒辦法啦！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"내가 돌파구를 마련할 테니까, 그 사이에……","JPN":"道を開くから、その隙に……","ENG":"I'll clear a path, you can–","TWN":"我會找到突破口的，在這期間……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_Q","text":{"KOREA":"이 땅에 역병의 안개가 점점 자욱해지는구나.","JPN":"この地に疫病の霧がどんどん濃くなっている。","ENG":"The fog of the plague is already thick in this land.","TWN":"這片大地上的瘟疫迷霧越來越濃了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_Q","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L19_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이 검은 갑옷은…? 모르스잖아……?","JPN":"この黒い鎧は……？　モールスじゃないか……？","ENG":"That black armor... Is that Mors...?!","TWN":"這副黑色盔甲是？是死神嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"모르스? 모르스가 왜 여기에……?","JPN":"モールス？　モールスがどうしてここに……？","ENG":"Mors? What's Mors doing here...?","TWN":"死神？死神怎麼會在這裡？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 세계는 이제 곧 종언을 맞이하게 될 터…….","JPN":"この世界はもうすぐ終焉を迎えるはず……","ENG":"The apocalypse will soon come to this world...","TWN":"這個世界即將迎來終結……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"어찌하여 안개의 땅에 함부로 발을 들인 것인가. 다른 곳에서 온 이방인들이여.","JPN":"なぜ霧の地に足を踏み入れた？　他地より来た異邦人たちよ。","ENG":"Why have you trespassed upon this fog-bound land, outsiders from beyond?","TWN":"為何擅自踏入迷霧之地，來自他鄉的外邦人。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"보세요, 라이카!","JPN":"見て、ライカ！","ENG":"Look, Laika!","TWN":"看啊，萊卡！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_04"},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"모르스가 침식체들을 날려버리고 있어요!","JPN":"モールスが侵食体を蹴散らしているわ！","ENG":"Mors is blowing the C.O.s away!","TWN":"死神正在把侵蝕體擊飛！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"저 녀석, 우리를 기억하지 못하는 것 같은데?","JPN":"あいつ、私たちのことを覚えていないようだぞ？","ENG":"I don't think she remembers us...","TWN":"那傢伙，好像不記得我們了？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐가 뭔지 하나도 모르겠지만, 저번에도 우리 편이었으니까 여기서도 우리 편이겠지……!","JPN":"何が何だかわからないけど、この前も味方してくれたんだ、ここでも同じだろ……！","ENG":"I don't know what's going on, but she helped us last time. So let's hope she's still on our side here...!","TWN":"雖然我完全不知道發生了什麼事？但上次是我們這邊的，所以這次應該也是我們這邊的！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"역병의 안개가 짙어지고 있으니, 이는 필히 돌이킬 수 없는 세계 종말의 징조일지어다.","JPN":"疫病の霧が濃くなってきている。これはきっと取り返しのつかない世界終末の前兆であろう。","ENG":"The fog of the plague still thickens. A sure sign of the world's irreversible collapse.","TWN":"瘟疫的迷霧愈發濃厚，這必定是不可逆轉的世界末日的徵兆。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"어서 돌아가거라, 소녀들이여. 이곳은 너희가 있을 곳이 아닐지니.","JPN":"ただちに戻れ、少女たちよ。ここはそなたたちがいてもいいところではない。","ENG":"You must turn back, young girls. This place is not meant for you.","TWN":"快回去吧，少女們。這裡不是你們該來的地方。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 이상 나아가고자 한다면, 틀림없이 그 작고 가냘픈 목숨을 잃게 될 것이다.","JPN":"これ以上進もうとするなら、その小さくか弱い命を落とすことになるだろう。","ENG":"If you keep going, your small, fragile lives will surely be lost.","TWN":"如果再進一步，毫無疑問，你那脆弱的生命將會不保。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"시끄러워, 검은 갑옷…! 위험하다는 소리는 이미 질릴 만큼 들었어……!","JPN":"うるさい、黒い鎧……！　危険だって話は飽きるほど聞いてきた……！","ENG":"Be quiet, black armor...! I've heard enough danger warnings to last a lifetime...!","TWN":"閉嘴，黑色盔甲！危險的話我已經聽膩了！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"여기서 꼬리 말고 내뺄 거면, 왜 이 염병할 다이빙 슈트를 입고 여기까지 왔겠냐고……!","JPN":"ここで尻尾巻いて逃げるつもりだったなら、このふざけたダイビングスーツ着てここまで来るかっての……！","ENG":"If I came all this way just to turn tail, I wouldn't have suited up in this damn diving suit to begin with...!","TWN":"如果現在要夾著尾巴逃跑，那我為什麼要穿上這該死的太空裝來到這裡！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"라이카, 말이 맞아요!","JPN":"ライカの言うとおりです！","ENG":"Laika's right!","TWN":"萊卡說得沒錯！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"우리는 여기서 그 아이를 찾아야만 해요, 모르스!","JPN":"私たちはここであの子を探さなきゃいけないんです、モールス！","ENG":"We have to find that kid, Mors!","TWN":"我們必須在這裡找到那個孩子，死神！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 아이라고……?","JPN":"あの子……？","ENG":"That kid...?","TWN":"那個孩子？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이름과 얼굴은 기억나지 않지만…….","JPN":"名前と顔は覚えていないんですけど……","ENG":"I don't remember her name or her face...","TWN":"雖然記不起名字和長相……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"기억 속의 그 아이는 늘 웃고 있었어요.","JPN":"記憶の中のあの子はいつも笑っていました。","ENG":"But in my memory, she always had a smile.","TWN":"記憶中的那個孩子總是在笑。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그 아이와 함께 했던 시간이, 나누었던 추억이 아직 제 가슴 속에 남아 있어요.","JPN":"あの子と一緒にいた時間が、一緒に作った思い出が、まだ私の心の中に残ってるんです。","ENG":"The time we spent together and the memories we shared are still with me.","TWN":"和那個孩子在一起的時間，以及分享的回憶仍然留在我的心裡。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"That's why...","TWN":"所以……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그러니까 우리는 이런 곳에서 멈춰 있을 수 없다고요……!","JPN":"だから私たちはここで立ち止まるわけにはいきません……！","ENG":"That's why we can't just stop here, not in a place like this...!","TWN":"所以，我們不能停留在這種地方！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"신성 반응 포착 완료……!","JPN":"神聖反応捕捉完了……！","ENG":"Divinity response detected...!","TWN":"神聖反應捕捉完畢！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"라이카, 망원경이 가리키는 방향은 이쪽이에요……!","JPN":"ライカ、望遠鏡が示す方向はこっちよ……！","ENG":"Laika, the Telescope's pointing this way...!","TWN":"萊卡，望遠鏡指向的方向是這邊！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"좋아, 망설일 시간 같은 건 없겠지!","JPN":"よし、迷ってる時間なんかない！","ENG":"Good. No time to second-guess ourselves now!","TWN":"好吧，沒有猶豫的時間了！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"가자고, 꼬맹이! 이번만큼은 늦지 않게 도착하는 거야……!","JPN":"行くぞ、おこちゃま！　今度は間に合わせるんだ……！","ENG":"Let's move, kid! This time, we're not showing up late...!","TWN":"走吧，小鬼！這次一定要準時到達！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이번만큼은 늦지 않겠다라…….","JPN":"今度は間に合わせる、か……","ENG":"Not showing up late this time...?","TWN":"這次不會遲到了……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"종말을 앞둔 이 세계의 단말마가 들려오는구나…….","JPN":"終末を目前にした、この世界の断末魔が聞こえる……","ENG":"The death throes of this dying world echo in my ears...","TWN":"末日就要來臨了……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 끔찍한 비명에 이끌려, 분명 불멸의 존재들이 나타날지니…….","JPN":"あの悲惨な悲鳴に惹かれ、きっと不滅の存在たちが現れるはず……","ENG":"Drawn by those dreadful screams, surely the undying shall appear once more...","TWN":"那些不滅之物肯定會被那可怕的尖叫聲所吸引……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"종국에는 이 또한 나의 우행에서 비롯된 죄일 터.","JPN":"終局においては、これもまた我の愚行に起因する罪であろう。","ENG":"In the end, this is also a sin that stems from my foolishness.","TWN":"最終，這也將是我的愚行所導致的罪過。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그렇다면 마지막까지 싸우는 것이 그나마 내 죄를 감내하는 유일한 길이겠지.","JPN":"であれば、最後まで戦うのが我の罪を耐え忍ぶ唯一の道。","ENG":"Then I shall fight to the very end as it is the only penance I have left.","TWN":"只有戰鬥到最後，才是我承受罪孽的唯一方式吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};